1	export type LiveCell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: LiveCell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (cell: LiveCell, liveSet: Set<string>): number =>
12	  NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
13	    liveSet.has(cellKey([cell[0] + dx, cell[1] + dy])),
14	  ).length;
15	
16	const isAliveNextGeneration = (isAlive: boolean, liveNeighbors: number): boolean =>
17	  liveNeighbors === 3 || (liveNeighbors === 2 && isAlive);
18	
19	const candidateCells = (liveCells: LiveCell[]): LiveCell[] => {
20	  const candidates = new Map<string, LiveCell>();
21	  for (const [x, y] of liveCells) {
22	    candidates.set(cellKey([x, y]), [x, y]);
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const cell: LiveCell = [x + dx, y + dy];
25	      candidates.set(cellKey(cell), cell);
26	    }
27	  }
28	  return [...candidates.values()];
29	};
30	
31	export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
32	  const liveSet = new Set(liveCells.map(cellKey));
33	  return candidateCells(liveCells).filter((cell) =>
34	    isAliveNextGeneration(liveSet.has(cellKey(cell)), countLiveNeighbors(cell, liveSet)),
35	  );
36	}
