1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when input is empty", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a pair of cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) as still life (each cell has 3 neighbors)", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map((c) => `${c[0]},${c[1]}`))).toEqual(
19	      new Set(["0,0", "1,0", "0,1", "1,1"]),
20	    );
21	  });
22	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
23	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
24	    const result = nextGeneration(input);
25	    expect(result).toHaveLength(3);
26	    expect(new Set(result.map((c) => `${c[0]},${c[1]}`))).toEqual(
27	      new Set(["-1,1", "0,1", "1,1"]),
28	    );
29	  });
30	  it("should birth a dead cell with exactly 3 live neighbors", () => {
31	    // L-tromino: ##  →  ##
32	    //           #.      ##
33	    const input: [number, number][] = [[0, 1], [1, 1], [0, 0]];
34	    const result = nextGeneration(input);
35	    expect(new Set(result.map((c) => `${c[0]},${c[1]}`))).toEqual(
36	      new Set(["0,0", "1,0", "0,1", "1,1"]),
37	    );
38	  });
39	  it.todo("should handle negative coordinates");
40	});
